import { useEffect, useState } from "react";

const WIDTH = 400;
const HEIGHT = 300;

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

export default function DuckHunt() {
  const [score, setScore] = useState(0);
  const [duck, setDuck] = useState({
    x: 0,
    y: 0,
    alive: false,
  });

  useEffect(() => {
    let running = true;

    async function gameLoop() {
      while (running) {
        setDuck({
          x: Math.random() * (WIDTH - 40),
          y: Math.random() * (HEIGHT - 40),
          alive: true,
        });

        await sleep(1500);

        if (!running) break;

        setDuck(duck => ({ ...duck, alive: false }));

        await sleep(200);
      }
    }

    gameLoop();

    return () => {
      running = false;
    };
  }, []);

  function shootDuck() {
    if (!duck.alive) return;

    setScore(score => score + 1);

    setDuck(duck => ({
      ...duck,
      alive: false,
    }));
  }

  return (
    <main>
      <h1>🔫 Duck Hunt</h1>

      <p>Score: {score}</p>

      <article
        style={{
          position: "relative",
          width: WIDTH,
          height: HEIGHT,
          border: "2px solid",
        }}
      >
        <button
          onClick={shootDuck}
          style={{
            position: "absolute",
            left: duck.x,
            top: duck.y,
            border: "none",
            background: "none",
            fontSize: "2.5rem",
          }}
        >
          {duck.alive ? "🦆" : "💥"}
        </button>
      </article>
    </main>
  );
}
